1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  // Simplest: empty input
6	  it("returns [] for an empty input (no living cells)", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	
10	  // Single cell — underpopulation (0 neighbors)
11	  it("single cell [(0,0)] dies from underpopulation -> []", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	
15	  // Rule 1: Underpopulation with two adjacent cells (each has 1 neighbor)
16	  it("Rule 1 underpopulation: [(0,1), (1,1)] both die (each has 1 neighbor) -> []", () => {
17	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
18	  });
19	
20	  // Rule 4: Reproduction — dead cell with exactly 3 live neighbors becomes alive
21	  // From spec: ##. / #.. / ... — cells [(0,0), (1,0), (0,1)]; dead (1,1) has 3 neighbors -> alive
22	  it("Rule 4 reproduction: dead cell (1,1) with exactly 3 live neighbors becomes alive", () => {
23	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
24	  });
25	
26	  // Rule 2: Survival — live cell with 2 or 3 neighbors lives on
27	  // From spec: ### / ... / .#. — center (1,1) has 3 live neighbors and survives
28	  it("Rule 2 survival: center cell (1,1) with 3 live neighbors survives to next generation", () => {
29	    // Gen 0: ### / .#. (live cells: (0,0), (1,0), (2,0), (1,1))
30	    // (1,1) has 3 live neighbors: (0,0), (1,0), (2,0) -> survives
31	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
32	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
33	  });
34	
35	  // Rule 3: Overpopulation — live cell with > 3 neighbors dies
36	  // From spec: ### / .#. / ### — center (1,1) has 4 neighbors -> dies
37	  it("Rule 3 overpopulation: center cell (1,1) with 4 live neighbors dies", () => {
38	    // Gen 0: ### / .#. / ### (live cells: (0,0), (1,0), (2,0), (1,1), (0,2), (1,2), (2,2))
39	    // (1,1) has 4 live neighbors: (0,0), (1,0), (2,0), (1,2) ... wait let me recount
40	    // Neighbors of (1,1): (0,0), (1,0), (2,0), (0,1), (2,1), (0,2), (1,2), (2,2)
41	    // Live among them: (0,0), (1,0), (2,0), (0,2), (1,2), (2,2) = 6 live neighbors
42	    // Actually with pattern ### / .#. / ### center has 6 neighbors (not 4)
43	    // Let me use pattern with exactly 4 neighbors:
44	    // ### / .#. / #.. -> (1,1) neighbors: (0,0)L, (1,0)L, (2,0)L, (0,2)L = 4 -> dies
45	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2]]);
46	    expect(result).not.toContainEqual([1, 1]);
47	  });
48	
49	  // Block (still life) — every live cell has exactly 3 neighbors, no dead cell gains 3
50	  it.todo("Block still life [(0,0), (1,0), (0,1), (1,1)] remains unchanged");
51	
52	  // Blinker (oscillator) — vertical to horizontal, also exercises negative coordinates in output
53	  it.todo("Blinker oscillator: vertical [(0,0), (0,1), (0,2)] becomes horizontal [(-1,1), (0,1), (1,1)]");
54	});
