1	export type Cell = [number, number];
2	
3	const coordKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const forEachNeighbor = (
6	  x: number,
7	  y: number,
8	  visit: (nx: number, ny: number) => void,
9	): void => {
10	  for (let dx = -1; dx <= 1; dx++) {
11	    for (let dy = -1; dy <= 1; dy++) {
12	      if (dx === 0 && dy === 0) continue;
13	      visit(x + dx, y + dy);
14	    }
15	  }
16	};
17	
18	export function nextGeneration(cells: Cell[]): Cell[] {
19	  const liveSet = new Set(cells.map(([x, y]) => coordKey(x, y)));
20	
21	  const countLiveNeighbors = (x: number, y: number): number => {
22	    let count = 0;
23	    forEachNeighbor(x, y, (nx, ny) => {
24	      if (liveSet.has(coordKey(nx, ny))) count++;
25	    });
26	    return count;
27	  };
28	
29	  const survivors: Cell[] = cells.filter(([x, y]) => {
30	    const neighborCount = countLiveNeighbors(x, y);
31	    return neighborCount === 2 || neighborCount === 3;
32	  });
33	
34	  const births: Cell[] = [];
35	  const considered = new Set<string>(liveSet);
36	  for (const [x, y] of cells) {
37	    forEachNeighbor(x, y, (nx, ny) => {
38	      const k = coordKey(nx, ny);
39	      if (considered.has(k)) return;
40	      considered.add(k);
41	      if (countLiveNeighbors(nx, ny) === 3) births.push([nx, ny]);
42	    });
43	  }
44	
45	  return [...survivors, ...births];
46	}
